import "../index.css";
import games from '../projects';
import { Link, useLocation, useParams, matchPath } from "react-router-dom";
import ReactMarkdown from 'react-markdown';
import React, { useEffect, useState } from "react";
import BreadCrumbs from '../BreadCrumbs'

function GetGame() {
  const params = useParams();

  return params["game"];
}

const PageComponent = ()=> {
  var game = GetGame();

  var file = games.filter(({ name }) => name == game)[0].file;

  let [ content, setContent] = useState({md: ""});

  useEffect(()=> {
      fetch(file)
          .then((res) => res.text())
          .then((md) => {
              setContent({ md })
          })
  }, [])

  return (
    <div className="post">
      <ReactMarkdown children={content.md}/>
    </div>
  )
}

const GameSubPage = ({game = ""}) => (
  <>
    <BreadCrumbs />
    <div className="main">
      <h1>
        {GetGame()}
      </h1>
      <PageComponent />
    </div>
  </>
)

export default GameSubPage;
